function solve(nums, k) {
  const n = nums.length;
  const prefix_mod = new Array(n + 1).fill(0);
  const mod_counts = { 0: 1 };
  let total_sum = 0;

  for (let i = 0; i < n; i++) {
    total_sum += nums[i];
    const mod = (total_sum % k + k) % k;
    prefix_mod[i + 1] = mod;
  }

  let min_sum = 0;
  for (let i = 0; i < n; i++) {
    const mod = (total_sum % k + k) % k;
    if (mod_counts[mod] > 0) {
      min_sum = Math.min(min_sum, total_sum - (mod_counts[mod] * k));
    }
    mod_counts[mod] += 1;
  }

  return min_sum;
}
